if !IsFeatureImplemented(FEAT_SM4) then EndOfDecode(Decode_UNDEF); end;
let d : integer{} = UInt(Rd);
let n : integer{} = UInt(Rn);

AArch64_CheckFPAdvSIMDEnabled();

let Vn : bits(128) = V{}(n);
var intval : bits(32);
var roundresult : bits(128);
var roundkey : bits(32);

roundresult = V{128}(d);
for index = 0 to 3 do
    roundkey = Vn[index*:32];

    intval = roundresult[127:96] XOR roundresult[95:64] XOR roundresult[63:32] XOR roundkey;

    for i = 0 to 3 do
        intval[i*:8]  = Sbox(intval[i*:8]);
    end;

    intval = intval XOR ROL(intval, 2) XOR ROL(intval, 10) XOR ROL(intval, 18) XOR ROL(intval, 24);
    intval = intval XOR roundresult[31:0];

    roundresult[31:0]   = roundresult[63:32];
    roundresult[63:32]  = roundresult[95:64];
    roundresult[95:64]  = roundresult[127:96];
    roundresult[127:96] = intval;
end;

V{128}(d) = roundresult;
